#!/bin/sh
set -eu
export NODE_PATH="/app/node_modules:${NODE_PATH:-}"
cd /app

SCRIPT_PATH="/app/scripts/import-users-csv.js"
if [ ! -f "$SCRIPT_PATH" ]; then
  SCRIPT_PATH="/tmp/import-users-csv.js"
  cat > /tmp/import-users-csv.js.b64 <<'SCRIPT_B64'

SCRIPT_B64
  base64 -d /tmp/import-users-csv.js.b64 > "$SCRIPT_PATH"
fi

cat > /tmp/users-state-phoubon.csv.b64 <<'CSV_B64'

CSV_B64
base64 -d /tmp/users-state-phoubon.csv.b64 > /tmp/users-state-phoubon.csv

node "$SCRIPT_PATH" /tmp/users-state-phoubon.csv
node - <<'NODE'
const { PrismaClient } = require('@prisma/client');
const prisma = new PrismaClient();
(async () => {
  const [total, staff, active, withUnit] = await Promise.all([
    prisma.user.count(),
    prisma.user.count({ where: { role: 'staff' } }),
    prisma.user.count({ where: { isActive: true } }),
    prisma.user.count({ where: { healthUnitId: { not: null } } }),
  ]);
  console.log(JSON.stringify({ total, staff, active, withUnit }, null, 2));
})()
  .catch((error) => { console.error(error); process.exit(1); })
  .finally(async () => { await prisma.$disconnect(); });
NODE